class Solution {
    public int calculate(String s) {
        s = s.trim();
        if (s.isEmpty()) {
            return 0;
        }
        int num = 0;
        char sign = '+';
        int result = 0;
        int stack = 0;
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (Character.isDigit(c)) {
                num = num * 10 + (c - '0');
            }
            if (c == '+' || c == '-' || c == '*' || c == '/' || i == s.length() - 1) {
                switch (sign) {
                    case '+':
                        result += num;
                        break;
                    case '-':
                        result -= num;
                        break;
                    case '*':
                        result *= num;
                        break;
                    case '/':
                        result /= num;
                        break;
                }
                num = 0;
                sign = c;
            }
        }
        return result;
    }
}
